import os
import sqlite3
import shutil
from flask import Flask, render_template, request, g

app = Flask(__name__)
app.config.from_object('config')

DB_PATH = '/tmp/verdant.db'
TEMPLATE_DB = '/app/verdant.db'

def get_db():
    if not os.path.exists(DB_PATH):
        shutil.copy(TEMPLATE_DB, DB_PATH)
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DB_PATH)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_connection(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def waf_filter(payload):
    # A basic filter that checks for specific lowercase keywords and spaces
    forbidden = ['union', 'select', 'from', 'where', ' ']
    for word in forbidden:
        if word in payload:
            return False
    return True

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')
        db = get_db()
        user = db.execute('SELECT * FROM users WHERE username = ? AND password = ?', (username, password)).fetchone()
        if user:
            return render_template('dashboard.html', user=user)
        return render_template('login.html', error="Invalid credentials")
    return render_template('login.html')

@app.route('/dashboard')
def dashboard():
    return render_template('dashboard.html')

@app.route('/inventory')
def inventory():
    db = get_db()
    silos = db.execute('SELECT * FROM silos').fetchall()
    return render_template('inventory.html', silos=silos)

@app.route('/yield-reports')
def yield_reports():
    crop_query = request.args.get('crop', '')
    results = []
    error = None

    if crop_query:
        if not waf_filter(crop_query):
            error = "Security Filter: Malicious character pattern or space detected!"
        else:
            try:
                db = get_db()
                # Vulnerable dynamic SQL construction
                query = f"SELECT name, yield_val, harvested_year FROM crops WHERE name = '{crop_query}'"
                cursor = db.execute(query)
                results = cursor.fetchall()
            except Exception as e:
                error = "Database Error occurred."

    return render_template('yields.html', results=results, error=error, query=crop_query)

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)

